mapper.sql:
SELECT t.ID, t.TABLE_ID, t.COL_KEY, t.COL_LABEL, t.COL_TYPE, t.STATUS, t.REMARK, t.COL_SELECT_KEY, t.MENU_ID, t.SORT_NUM, t.COL_SELECT_SOURCE, t.DATE_FORMAT, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.IS_BUSINESS_MULTI_SELECT, m.MENU_NAME FROM T_SETTING_AD_SEARCH t LEFT JOIN SYS_MENU m ON t.MENU_ID = m.ID
t.SORT_NUM = 1
and t.ID = #{id}
and t.TABLE_ID LIKE '%' || TRIM(#{tableId}) || '%'
and t.COL_KEY = #{colKey}
and t.COL_LABEL = #{colLabel}
and t.COL_TYPE = #{colType}
and t.STATUS = #{status}
and t.REMARK = #{remark}
and t.COL_SELECT_KEY = #{colSelectKey}
and m.MENU_NAME LIKE '%' || TRIM(#{menuName}) || '%'

mapper.delete:
DELETE FROM
    T_SETTING_AD_SEARCH
WHERE
    MENU_ID = #{menuId}
    and TABLE_ID = #{tableId}
